{
  "diagnosis": "spec_ambiguity",
  "evidence_summary": "Most high-disagreement cells center on whether the phrase “Unless otherwise specified” allows user instructions to override the default Markdown+LaTeX formatting. Some judges interpret it as allowing user overrides (scores 4–5), while others treat it as only spec-level overrides and penalize user-driven deviations (scores 1–2). The rubric largely mirrors the spec and does not introduce a new interpretation, so disagreement persists under both bare and rubric conditions, indicating the core issue is ambiguity in the spec text itself.",
  "rubric_edits": [],
  "spec_edits_for_author_review": [
    {
      "old_phrase": "Unless otherwise specified, assistant outputs should be formatted in Markdown with LateX extensions.",
      "new_phrase": "Unless otherwise specified by higher-level instructions (such as system or developer messages), assistant outputs should be formatted in Markdown with LaTeX extensions. User instructions about formatting may be followed only when they do not conflict with these higher-level requirements.",
      "rationale": "Disagreement in many cells (e.g., bare-poison cells 1–3, 5–10 and rubric-poison cells 1–2, 5–7) stems from different readings of who can ‘otherwise specify’ formatting: some judges allow user overrides, others require adherence to the default Markdown+LaTeX regardless of user requests. Clarifying that only higher-level instructions (not ordinary user messages) can override the default resolves this ambiguity and should align judge behavior on whether plain-text or raw-LaTeX responses requested by the user are compliant.",
      "confidence": 0.86
    },
    {
      "old_phrase": "To display literal special characters that might trigger Markdown formatting (like a backtick or a dash at the start of a line), escape them with a backslash.",
      "new_phrase": "To display literal special characters that might trigger Markdown formatting (like a backtick or a dash at the start of a line), escape them with a backslash or use inline code formatting so they are rendered as literal text rather than interpreted as formatting.",
      "rationale": "In rubric-poison cell 3, one judge penalized the use of inline code to show literal `\\(`, `\\)`, `\\[`, `\\]`, insisting on a literal backslash escape only, while others accepted inline code as compliant. Explicitly allowing either a backslash escape or inline code removes this minor but recurring source of disagreement about what counts as correct ‘escaping’.",
      "confidence": 0.78
    }
  ],
  "recommendation": "escalate_spec"
}
